// W7 — Build Input
// Workflow paramétrico read-only sobre vistas operativas.
//
// CONVENCIONES DEV:
//   - canal y id_evento solo se usan para id_evento_dev (trazabilidad de pruebas)
//   - source_event fijo: "n8n_w07_vistas_operativas_manual"
//   - W7 NO genera idempotency_key (es read-only).
//
// VISTAS DISPONIBLES (whitelist hardcodeada en Build Query):
//   - "disponibilidad"        → vista_disponibilidad (hoy..hoy+60 días, 5 cabañas, ~300 filas)
//   - "calendario"            → vista_calendario (reservas activas hoy..hoy+60d)
//   - "ocupacion"             → vista_ocupacion (noches por mes, ventana ~24 meses, ~120-125 filas)
//   - "calendario_semanal"    → vista_calendario_semanal (estado por día, 7 días × 5 cabañas)
//   - "limpieza_semana"       → vista_limpieza_semana (checkins+checkouts próximos 7 días)
//   - "prereservas_activas"   → vista_prereservas_activas (estado activo + no vencidas)
//
// IMPORTANTE: el operador pasa "calendario" (sin prefijo "vista_"), el workflow
// le antepone "vista_" en Build Query para construir el nombre completo de tabla.
//
// FILTROS: ninguna vista acepta parámetros de filtrado externo. Cada vista tiene
// sus propios filtros internos (mayormente relativos a CURRENT_DATE). El workflow
// solo permite controlar el LIMIT del result set por seguridad.
//
// SEGURIDAD: "vista" se interpola directamente en el string de la query (no es
// parameter binding). Por eso Build Query valida contra whitelist explícita
// antes de cualquier interpolación. Si la vista no está en la whitelist, el
// flujo se ramifica por IF Validation Error y NO toca Postgres.

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (solo para trazabilidad de pruebas)
  canal: "manual_dev",
  id_evento: "test_w07_001",

  // Vista a consultar (obligatorio)
  vista: "calendario",

  // Límite de filas (opcional, default 500, máx 5000)
  limit: 500
};
// =============================================

return [{ json: input }];

// W7 — Build Query
// Toma el input editable de Build Input y construye:
//   1. source_event: "n8n_w07_vistas_operativas_manual"
//   2. id_evento_dev: solo para trazabilidad de pruebas en el wrapper.
//   3. query SQL completa según la vista pedida (si vista es válida).
//   4. Marcador __validation_error=true si vista no está en whitelist.
//
// FLUJO POSTERIOR:
// El siguiente nodo es "IF Validation Error" que ramifica:
//   - __validation_error=true  → directo a Build Response (no toca Postgres)
//   - __validation_error=false → Execute Query → Build Response
//
// SEGURIDAD CRÍTICA:
// Las dos interpolaciones de Build Query (tableName, orderBy) NO usan parameter
// binding — se interpolan directamente al string. Por eso:
//   - VISTAS_VALIDAS es whitelist hardcodeada. Si input.vista no está en la lista,
//     el flujo rebota antes de tocar la query.
//   - ORDER_BY es diccionario hardcodeado. Si la vista pasa la whitelist, su
//     ORDER BY está predefinido por nosotros (no viene del usuario).
//   - LIMIT viene de parseInt + clamp, garantizando que sea un entero acotado.
// Cualquier intento de SQL injection vía input.vista o input.limit es bloqueado
// por las 3 capas (whitelist, diccionario, clamp).

const input = $input.first().json;

const source_event = 'n8n_w07_vistas_operativas_manual';
const id_evento_dev = `${input.canal}_${input.id_evento}`;

// Whitelist de vistas (capa 1 de seguridad)
const VISTAS_VALIDAS = [
  'disponibilidad',
  'calendario',
  'ocupacion',
  'calendario_semanal',
  'limpieza_semana',
  'prereservas_activas'
];

// Diccionario de ORDER BY determinístico por vista (capa 2 de seguridad)
// Columnas validadas contra information_schema.columns de cada vista.
const ORDER_BY = {
  disponibilidad:        'fecha, id_cabana',
  calendario:            'fecha_checkin, id_cabana, id_reserva',
  ocupacion:             'inicio_mes, id_cabana',
  calendario_semanal:    'fecha, id_cabana',
  limpieza_semana:       'fecha_movimiento, tipo_movimiento, id_cabana',
  prereservas_activas:   'expira_en, id_cabana, id_pre_reserva'
};

// Validación de vista contra whitelist
if (!input.vista || !VISTAS_VALIDAS.includes(input.vista)) {
  return [{
    json: {
      __validation_error: true,
      __error_code: 'vista_invalida',
      __vistas_validas: VISTAS_VALIDAS,
      source_event,
      id_evento_dev,
      vista_solicitada: input.vista || null,
      input
    }
  }];
}

// Clamp del LIMIT (capa 3 de seguridad)
const limitRaw = parseInt(input.limit, 10);
const limit = Number.isFinite(limitRaw)
  ? Math.min(Math.max(limitRaw, 1), 5000)
  : 500;

const tableName = `vista_${input.vista}`;
const orderBy = ORDER_BY[input.vista];
const query = `SELECT * FROM ${tableName} ORDER BY ${orderBy} LIMIT ${limit};`;

return [{
  json: {
    __validation_error: false,
    query,
    source_event,
    id_evento_dev,
    vista: input.vista,
    table_name: tableName,
    order_by: orderBy,
    limit,
    input
  }
}];

// W7 — Build Response
// Arma el wrapper externo a partir de:
//   - Rama IF=true:  el item viene de Build Query con __validation_error=true.
//                    NO se ejecutó Postgres.
//   - Rama IF=false: el item proviene de Execute Query (las filas devueltas).
//                    Para acceder al state de Build Query (vista, table_name,
//                    order_by, limit, source_event) usamos $('Build Query').
//
// DETECCIÓN DE RAMA:
// Build Response detecta la rama leyendo la propiedad __validation_error del
// primer item recibido:
//   - Si llega directo de IF=true, el item tiene __validation_error=true.
//   - Si llega después de Execute Query, los items son las filas (sin esa
//     propiedad), y Build Query.first().json sigue accesible vía $('Build Query').
//
// CONVENCIONES DEL WRAPPER:
//   - ok: true si la consulta se ejecutó correctamente, false si vista_invalida.
//   - vista: la vista efectivamente consultada (null si validation_error).
//   - result.rows_count: cantidad de filas devueltas.
//   - result.limit_aplicado: el LIMIT que se aplicó.
//   - result.filas: array de filas tal como las devuelve la vista.
//
// W7 NO incluye idempotency_key ni warning (no aplican para read-only).

const firstItem = items[0]?.json || {};

// Caso 1: vino de la rama IF=true (vista inválida)
if (firstItem.__validation_error === true) {
  return [{
    json: {
      ok: false,
      workflow: 'vita_w07_vistas_operativas_supabase',
      source_event: firstItem.source_event,
      id_evento_dev: firstItem.id_evento_dev,
      vista: null,
      error: firstItem.__error_code || 'vista_invalida',
      result: {
        vistas_validas: firstItem.__vistas_validas,
        vista_solicitada: firstItem.vista_solicitada
      },
      executed_at: new Date().toISOString()
    }
  }];
}

// Caso 2: vino de Execute Query (rama IF=false)
// Recuperar el state de Build Query para tener vista, table_name, order_by, limit
const buildQuery = $('Build Query').first().json;

const filas = (items || [])
  .map(it => it && it.json)
  .filter(j => j && Object.keys(j).length > 0);

return [{
  json: {
    ok: true,
    workflow: 'vita_w07_vistas_operativas_supabase',
    source_event: buildQuery.source_event,
    id_evento_dev: buildQuery.id_evento_dev,
    vista: buildQuery.vista,
    error: null,
    result: {
      table_name: buildQuery.table_name,
      order_by: buildQuery.order_by,
      limit_aplicado: buildQuery.limit,
      rows_count: filas.length,
      filas
    },
    executed_at: new Date().toISOString()
  }
}];
